// Set up a logger
Logger _logger = Logger('AppLogger');

void logHttpRequest(http.BaseRequest request) {
  String message = "HTTP Request:\nMethod: ${request.method}\nUrl: ${request.uri}\nHeaders: ${request.headers}";
  
  if (request is http.MultipartRequest) {
    message += "\nBody: ${(request as http.MultipartRequest).fields}";
  } else if (request is http.FormDataRequest) {
    message += "\nBody: ${(request as http.FormDataRequest).fields}";
  } else {
    message += "\nBody: ${request.bodyBytes}";
  }
  
  _logger.finer(message);
}

void logHttpResponse(http.BaseResponse response) {
  String message = "HTTP Response:\nStatus: ${response.statusCode}\nHeaders: ${response.headers}";

  if (response is http.MultipartResponse || response is http.FormDataResponse) {
    message += "\nBody: ${response.bodyBytes}";
  } else {
    message += "\nBody: ${(response as http.StringResponse).body}";
  }
  
  _logger.finer(message);
}

